import axios from "axios"
import { toast } from "react-toastify"
import { refreshToken } from "./jwt-handler"
import APIEndPoints from "../../consts/api-end-points"

type APIRequestParams = {
  method: string
  url: string
  operation?: string
  sp_name?: string
  data?: Record<string, any> | any
  useAuthorize?: boolean
}

export const httpRequest = async ({
  method,
  url,
  operation = "",
  sp_name = "",
  data = {},
  useAuthorize = true
}: APIRequestParams): Promise<any> => {
  let response: any
  data = {
    ...{ Operation: operation },
    ...data,
    ...{ DatabaseIP: APIEndPoints.db_ib, DatabaseName: APIEndPoints.dbname }
  }
  await axios({
    method: method,
    url: url,
    headers: useAuthorize
      ? {
          sp_name: sp_name,
          Authorization: "Bearer " + APIEndPoints.accessToken
        }
      : {
          sp_name: sp_name
        },
    data: data,
    params: method === "POST" ? null : data
  })
    .then((res) => {
      response = res
    })
    .catch(function (e) {
      response = e.response ?? {}
    })
  switch (response?.status) {
    case 200:
      if (response?.data?.State !== 0) {
        toast.error(response.data?.Message ?? "An error occurred", {
          position: "top-center"
        })
      }
      break
    case 400:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case 401:
      if (useAuthorize) {
        const res = (await refreshToken()) as any
        if (res?.status === 200)
          return await httpRequest({ method, url, operation, sp_name, data, useAuthorize })
      } else {
        toast.error(JSON.stringify(response.data.message ?? {}), {
          position: "top-center"
        })
      }
      break
    case 500:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case undefined:
      toast.error("Cannot connect to server", {
        position: "top-center"
      })
      break
    default:
      toast.error(response.data?.toString() ?? "", {
        position: "top-center"
      })
      break
  }
  return response
}
